import requests
import json

class PaperSummarizer:
    def __init__(self, api_key):
        self.api_key = api_key
        self.api_url = "https://api.claude.ai/summarize"

    def summarize_paper(self, paper_text):
        headers = {
            "Authorization": f"Bearer {self.api_key}",
            "Content-Type": "application/json"
        }
        data = {
            "text": paper_text
        }
        response = requests.post(self.api_url, headers=headers, data=json.dumps(data))
        if response.status_code == 200:
            return response.json()["summary"]
        else:
            return None

    def ask_question(self, summary, question):
        api_url = "https://api.claude.ai/answer"
        headers = {
            "Authorization": f"Bearer {self.api_key}",
            "Content-Type": "application/json"
        }
        data = {
            "summary": summary,
            "question": question
        }
        response = requests.post(api_url, headers=headers, data=json.dumps(data))
        if response.status_code == 200:
            return response.json()["answer"]
        else:
            return None

def main():
    api_key = "YOUR_API_KEY_HERE"
    summarizer = PaperSummarizer(api_key)
    paper_text = input("Enter the paper text: ")
    summary = summarizer.summarize_paper(paper_text)
    if summary:
        print("Summary:", summary)
        while True:
            question = input("Enter a question about the summary (or 'quit' to exit): ")
            if question.lower() == "quit":
                break
            answer = summarizer.ask_question(summary, question)
            if answer:
                print("Answer:", answer)
            else:
                print("Failed to get answer")
    else:
        print("Failed to summarize paper")

if __name__ == "__main__":
    main()

